import { test, expect } from '@playwright/test';

test('should display mocked user data', async ({ page }) => {
  await page.route('**/api/user', async (route) => {
    await route.fulfill({
      contentType: 'application/json',
      body: JSON.stringify({
        name: 'Mock User',
        email: 'mock@test.com',
        xp: 9999
      })
    });
  });
  await page.goto('/app/dashboard.html');
  await expect(page.locator('#user-name')).toHaveText('Mock User');
  await expect(page.locator('#user-email')).toHaveText('mock@test.com');
  await expect(page.locator('#user-xp')).toHaveText('9999');
});

