import { test, expect } from '@playwright/test';

test('should redirect unauthenticated user', async ({ page }) => {
  await page.goto('/app/dashboard.html');
  await expect(page).toHaveURL(/.*login/);
});

test('should clear session on logout', async ({ page }) => {
  await page.goto('/app/login.html');
  await page.evaluate(() => localStorage.setItem('twe_session', '{"username":"user"}'));
  await page.goto('/app/dashboard.html');
  await page.click('#logout-btn');
  const session = await page.evaluate(() => localStorage.getItem('twe_session'));
  expect(session).toBeNull();
});
